import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        // Limit the buffer size to a safe value to prevent buffer overflow
        int bufferSize = Math.min(userInput.length(), 10); // Setting a maximum buffer size of 10

        char[] buffer = new char[bufferSize];

        // Copy user input into the buffer after ensuring it fits within the buffer size
        userInput.getChars(0, bufferSize, buffer, 0);

        System.out.println("Hello, " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
